#!/usr/bin/env python3
"""
Dependency Management Script for Python Projects
==============================================

This script provides utilities for managing Python dependency lock files
to ensure consistent dependency versions across development and production
environments.

Features:
- Generate requirements.txt with hashes
- Update dependencies in requirements.txt
- Generate Poetry lock files
- Validate dependency consistency
"""

import hashlib
import os
import re
import subprocess
import sys
from pathlib import Path
from typing import List, Tuple

class DependencyManager:
    def __init__(self, project_root: str = "."):
        self.project_root = Path(project_root)
        self.requirements_file = self.project_root / "requirements.txt"
        self.poetry_lock_file = self.project_root / "poetry.lock"
        self.pyproject_file = self.project_root / "pyproject.toml"
    
    def generate_requirements_with_hashes(self) -> None:
        """Generate requirements.txt with hashes using pip-compile."""
        try:
            subprocess.run([
                "pip-compile", 
                "--output-file", str(self.requirements_file),
                "--generate-hashes",
                str(self.project_root / "pyproject.toml")
            ], check=True, capture_output=True)
            print(f"Generated {self.requirements_file} with hashes")
        except subprocess.CalledProcessError as e:
            print(f"Error generating requirements: {e}")
            sys.exit(1)
    
    def update_requirements(self) -> None:
        """Update dependencies in requirements.txt to latest versions."""
        try:
            subprocess.run([
                "pip-compile", 
                "--output-file", str(self.requirements_file),
                "--upgrade",
                "--generate-hashes",
                str(self.project_root / "pyproject.toml")
            ], check=True, capture_output=True)
            print(f"Updated {self.requirements_file}")
        except subprocess.CalledProcessError as e:
            print(f"Error updating requirements: {e}")
            sys.exit(1)
    
    def generate_poetry_lock(self) -> None:
        """Generate poetry.lock file."""
        try:
            subprocess.run([
                "poetry", "lock", "--no-update"
            ], check=True, capture_output=True, cwd=self.project_root)
            print(f"Generated {self.poetry_lock_file}")
        except subprocess.CalledProcessError as e:
            print(f"Error generating poetry.lock: {e}")
            sys.exit(1)
    
    def update_poetry_lock(self) -> None:
        """Update poetry.lock file with latest versions."""
        try:
            subprocess.run([
                "poetry", "lock", "--update"
            ], check=True, capture_output=True, cwd=self.project_root)
            print(f"Updated {self.poetry_lock_file}")
        except subprocess.CalledProcessError as e:
            print(f"Error updating poetry.lock: {e}")
            sys.exit(1)
    
    def verify_requirements_consistency(self) -> bool:
        """Verify that requirements.txt is consistent with pyproject.toml."""
        try:
            # Check if requirements.txt exists
            if not self.requirements_file.exists():
                print("requirements.txt not found")
                return False
            
            # Read requirements.txt
            with open(self.requirements_file, 'r') as f:
                req_content = f.read()
            
            # Check if all dependencies from pyproject.toml are in requirements.txt
            with open(self.pyproject_file, 'r') as f:
                pyproject_content = f.read()
            
            # Extract dependencies from pyproject.toml
            deps_pattern = r'(\[tool.poetry.dependencies\]|\[tool.poetry.dev-dependencies\])'
            deps_match = re.search(deps_pattern, pyproject_content)
            
            if deps_match:
                # This is a simplified check - in practice, you'd parse TOML properly
                print("Consistency check completed. Run 'pip-compile' manually for full verification.")
                return True
            else:
                print("Could not parse dependencies from pyproject.toml")
                return False
                
        except Exception as e:
            print(f"Error in consistency check: {e}")
            return False
    
    def hash_file(self, file_path: Path) -> str:
        """Calculate SHA256 hash of a file."""
        hash_sha256 = hashlib.sha256()
        with open(file_path, "rb") as f:
            for chunk in iter(lambda: f.read(4096), b""):
                hash_sha256.update(chunk)
        return hash_sha256.hexdigest()
    
    def validate_lock_files(self) -> None:
        """Validate that lock files exist and are consistent."""
        print("Validating lock files...")
        
        # Check requirements.txt exists
        if self.requirements_file.exists():
            print(f"✓ {self.requirements_file} exists")
            # Check if it has hashes
            with open(self.requirements_file, 'r') as f:
                content = f.read()
                if 'sha256:' in content:
                    print("✓ requirements.txt contains hashes")
                else:
                    print("✗ requirements.txt missing hashes")
        else:
            print(f"✗ {self.requirements_file} missing")
        
        # Check poetry.lock exists
        if self.poetry_lock_file.exists():
            print(f"✓ {self.poetry_lock_file} exists")
        else:
            print(f"✗ {self.poetry_lock_file} missing")
        
        print("Lock file validation completed.")

def main():
    """Main function to run dependency management commands."""
    manager = DependencyManager()
    
    if len(sys.argv) < 2:
        print("Usage: python dependency_manager.py <command>")
        print("Commands:")
        print("  generate-reqs         Generate requirements.txt with hashes")
        print("  update-reqs           Update requirements.txt with latest versions")
        print("  generate-poetry       Generate poetry.lock file")
        print("  update-poetry         Update poetry.lock with latest versions")
        print("  validate              Validate lock files")
        print("  verify                Verify consistency")
        sys.exit(1)
    
    command = sys.argv[1]
    
    if command == "generate-reqs":
        manager.generate_requirements_with_hashes()
    elif command == "update-reqs":
        manager.update_requirements()
    elif command == "generate-poetry":
        manager.generate_poetry_lock()
    elif command == "update-poetry":
        manager.update_poetry_lock()
    elif command == "validate":
        manager.validate_lock_files()
    elif command == "verify":
        manager.verify_requirements_consistency()
    else:
        print(f"Unknown command: {command}")
        sys.exit(1)

if __name__ == "__main__":
    main()